  import java.sql.Connection;
  import java.sql.Statement;
  import java.sql.DriverManager;
  import java.sql.ResultSet;
  import java.sql.SQLException;
  import sailpoint.tools.Util;
  import sailpoint.object.Application;
  
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;
  
	/**
	 * @ used to get the DB details from application.
	 * @ void
	 * @throws Exception
	 */
  public void getConnectionDetails(String applicationName){
    logger.debug("getConnectionDetails Starting");
    try{
      if(Util.isNotNullOrEmpty(applicationName)){
        Application application = context.getObjectByName(Application.class, applicationName);
        if(application !=null){
          driver = application.getStringAttributeValue("driverClass");
          pwd = context.decrypt(application.getStringAttributeValue("password"));
          url = application.getStringAttributeValue("url");
          user = application.getStringAttributeValue("user");
		  context.decache(application);
        }
      }
    }catch(Exception e){
      logger.error("Excetion in get Connection Details "+e.getMessage());
    }
     logger.debug("getConnectionDetails Exiting");
  }

  /**
	 * @ used to get the DB connection object.
	 * @return return connection object
	 * @throws SQLException
	 * @throws Exception
	 */
  public Connection getConnection() throws SQLException,Exception{
    logger.debug("getconnection Starting");
    try {
      Class.forName(driver);
    } catch (ClassNotFoundException e) {
      logger.error("Connection Driver class not found ::"+e.getMessage());
    }
    try {
      dbConnection = DriverManager.getConnection(url, user, pwd);
    } catch (SQLException e) {
      logger.error("Connection Fail :: "+e.getMessage());
    }
    logger.debug("getconnection Ending");
    return dbConnection;
  }
  
// Logic starts from here
  static Log logger = LogFactory.getLog("rule.Ascension-Rule-AllowedValues-DocType");
	logger.debug("Entering Ascension-Rule-AllowedValues-DocType");
  public String driver;
  public String url;
  public String user;
  public String pwd;
  public String applicationName = "Doctor Master";
  public Connection dbConnection = null;
  String sql = "SELECT InvDocType FROM DocTypeXwalk";
  Set<String> resultSet = new HashSet<String>();
  ArrayList resultList = new ArrayList();
  Statement stmt = null;
  ResultSet rs = null;

  try {
    getConnectionDetails(applicationName);
    dbConnection=getConnection();

    if (dbConnection != null) {
      stmt = dbConnection.createStatement();
      rs = stmt.executeQuery(sql);

      while (rs!=null && rs.next()) {
        if(Util.isNotNullOrEmpty(rs.getString("InvDocType"))){
          resultSet.add(rs.getString("InvDocType"));
        }
      }
    }
  } catch (SQLException e) {
    logger.error("Excetion in DB Operation "+e.getMessage());
  } catch (Exception e) {
    logger.error("Excetion "+e.getMessage());
  }finally{
    try {
      if (rs != null) {
        rs.close();
      }
    } catch (SQLException e) {
      logger.error("Excetion in closeing DB object "+e.getMessage());
    }
    try {
      if (stmt != null) {
        stmt.close();
      }
    } catch (SQLException e) {
      logger.error("Excetion in closeing DB object "+e.getMessage());
    }
    if (dbConnection != null) {
      try {
        dbConnection.close();
      } catch (SQLException e) {
        logger.error("Excetion in closeing connection "+e.getMessage());
      }
    }
  }

  resultList.addAll(resultSet);
  Collections.sort(resultList);
  logger.debug("Exiting Ascension-Rule-AllowedValues-DocType");
  return resultList;
